
import React, { useState } from 'react'
import { useSelector, useDispatch } from 'react-redux'
//import * as _Util from '../store/Util'

// import styles from './btns.module.css'

import {CloseModal} from "../../actions/common";
import { Icon_Cmpt } from '.';

const Icon2 = Icon_Cmpt();



const useObserveChanges = () => {
  const observeChanges =  useSelector(state => state.observeChanges);
  const dispatch = useDispatch()
  const close = (Id) => {
    CloseModal(dispatch,{id:Id});
  }

  return { observeChanges,  close }
}


const BTN_QTY = (props) => {  
  const {qty, max} = props;

  const _plus = () =>{
    if(typeof props.upd === "function"){
      if(!(max && qty>=max)){
        props.upd(qty+1)
      }
    }
  }

  const _minus = () =>{
    if(typeof props.upd === "function"){
      if(qty>1){
        props.upd(qty-1)
      }
    }
  }
  
  return (
    <>      
      <div className={'qty_btn _dsplFlx'}>
        <div className="flexSpace"/>
        <div className={` icon_open down`} style={{opacity:qty>1?1:0}}  onClick={()=>_minus()}>
          <Icon2 name={"arrow_down"} />
        </div>
        <div className="flexSpace"/>
        <div className={`qty_value`}>
        {qty}
        </div>
        <div className="flexSpace"/>
        <div className={`icon_open up`} style={{opacity:max?qty<max?1:0:1}} onClick={()=>_plus()}>
          <Icon2 name={"arrow_down"} />
        </div>
        <div className="flexSpace"/>
      </div>
    </>
  )
}


export default BTN_QTY;


